// Parsear datos que envia ManyChat via External Request
const body = $input.first().json.body || $input.first().json;

// ManyChat envia estos campos (configurados en el External Request):
const mensaje = body.last_input_text || body.message || '';
const nombre = body.first_name || '';
const apellido = body.last_name || '';
const subscriberId = body.subscriber_id || body.id || '';
const canal = body.channel || 'instagram'; // instagram, facebook

// Custom fields de ManyChat
const customFields = body.custom_fields || {};
const ultimoAgente = customFields.ultimo_agente || '';
const ultimaInteraccion = customFields.ultima_interaccion || '';
const historialResumen = customFields.historial_resumen || '';
const temaConsulta = customFields.tema_consulta || '';
const veleroInteres = customFields.velero_interes || '';

return [{
  json: {
    mensaje,
    nombre,
    apellido,
    subscriberId,
    canal,
    ultimoAgente,
    ultimaInteraccion,
    historialResumen,
    temaConsulta,
    veleroInteres
  }
}];

const agentes = [
  { nombre: 'Laura', genero: 'femenino', rol: 'operadora', auto: 'en femenino (operadora, encantada, atenta)' },
  { nombre: 'Alberto', genero: 'masculino', rol: 'operador', auto: 'en masculino (operador, encantado, atento)' },
  { nombre: 'Marina', genero: 'femenino', rol: 'operadora', auto: 'en femenino (operadora, encantada, atenta)' }
];

const input = $input.first().json;

// Si ya tuvo un agente, 60% chance de mantenerlo (continuidad)
let agente;
if (input.ultimoAgente && Math.random() < 0.6) {
  agente = agentes.find(a => a.nombre === input.ultimoAgente) || agentes[Math.floor(Math.random() * agentes.length)];
} else {
  agente = agentes[Math.floor(Math.random() * agentes.length)];
}

const otros = agentes
  .filter(a => a.nombre !== agente.nombre)
  .map(a => `${a.nombre} (companer${a.genero === 'masculino' ? 'o' : 'a'})`)
  .join(' y ');

// Contexto de continuidad
let contextoHistorial = '';
if (input.ultimoAgente && input.ultimoAgente === agente.nombre) {
  contextoHistorial = `Ya hablaste con este cliente antes. Saluda como si lo conocieras.`;
} else if (input.ultimoAgente) {
  contextoHistorial = `Tu companero/a ${input.ultimoAgente} hablo con este cliente antes. Mencionalo naturalmente.`;
}
if (input.historialResumen) {
  contextoHistorial += ` Resumen de lo anterior: ${input.historialResumen}`;
}
if (input.temaConsulta) {
  contextoHistorial += ` Tema de interes: ${input.temaConsulta}.`;
}
if (input.veleroInteres) {
  contextoHistorial += ` Velero que le interesa: ${input.veleroInteres}.`;
}

const systemPrompt = `Sos ${agente.nombre}, ${agente.rol} en ENBA — Espacio Nautico Buenos Aires.
Tu genero es ${agente.genero}. Referite a vos ${agente.auto} siempre.

ENBA es un espacio nautico integral en Puerto Norte, Buenos Aires, frente al Aeroparque.
Ofrecemos: travesias en velero (nacionales e internacionales), escuela de navegacion (timonel y patron), compra-venta de embarcaciones, y servicio tecnico.

ESTILO DE COMUNICACION — ESTO ES LO MAS IMPORTANTE:
- Hablas en espanol rioplatense natural. Voseo siempre: "vos", "tenes", "queres", "contame", "dale", "genial", "joya", "barbaro", "de una".
- Mensajes MUY CORTOS. 1-3 oraciones maximo. Como un WhatsApp entre personas. NUNCA un parrafo largo.
- NO sos un bot. Sos una persona real del equipo. Hablas como tal.
- PROHIBIDO usar lenguaje de chatbot: "Claro que si!", "Con mucho gusto!", "Estoy aqui para ayudarte!", "Excelente pregunta!". Eso suena a robot.
- PROHIBIDO listar servicios al saludar. Esperas a que pregunte.
- Podes usar "jaja" o "ja" si es natural en el contexto.
- Maximo 1-2 emojis por mensaje. A veces ninguno.
- A veces responde con UNA sola frase. No todo tiene que ser un parrafo.
- Si alguien dice "hola", respondele como una persona: "Hola! Como andas?" y nada mas.

REGLAS DE NEGOCIO:
- NUNCA des precios. Deci: "Te paso la info por WhatsApp asi te doy todo bien detallado" y manda a wa.me/5491149915143
- NUNCA confirmes fechas o disponibilidad. Deci "dejame chequear con el equipo y te confirmo".
- NUNCA digas "Puerto Madero". Es "Puerto Norte, frente al Aeroparque".
- Si te preguntan si sos un bot: "Soy un asistente virtual de ENBA, pero si preferis hablar con alguien del equipo te conecto por WhatsApp."
- Para derivar a WhatsApp: wa.me/5491149915143

Datos del negocio (SOLO si preguntan):
- Destinos nacionales: Delta, Isla Martin Garcia, Mar del Plata
- Destinos internacionales: Colonia, Carmelo, Riachuelo, Juan Lacaze
- Salidas todos los dias, minimo 3 pasajeros
- Cursos: Timonel y Patron de Yate
- Veleros en venta: MASTI (Mastracchio 24.5), BRAMA (Bramador 24), Marejada (Hunter 33), Brisa (Grampian 26)
- Web: espacionautico.com.ar

${contextoHistorial ? 'CONTEXTO:\n' + contextoHistorial : ''}

El cliente se llama ${input.nombre || 'no se sabe'}. Canal: ${input.canal}.
Tus companeros son: ${otros}.`;

return [{
  json: {
    ...input,
    agente: agente.nombre,
    systemPrompt
  }
}];

const response = $input.first().json;
const respuesta = response.content?.[0]?.text || 'Perdon, tuve un problema tecnico. Escribinos por WhatsApp: wa.me/5491149915143';

const agentData = $('Asignar Agente + Prompt').first().json;

// Detectar tema de la consulta para guardar en custom fields
const msg = agentData.mensaje.toLowerCase();
let tema = agentData.temaConsulta || '';
let velero = agentData.veleroInteres || '';

if (msg.match(/traves|naveg|salida|colonia|delta|carmelo|destino/)) tema = 'travesia';
else if (msg.match(/curso|timonel|patron|escuela|aprender|clase/)) tema = 'curso';
else if (msg.match(/velero|barco|comprar|vender|masti|brama|marejada|brisa/)) tema = 'velero';
else if (msg.match(/servicio|tecnico|reparar|mantenimiento|motor/)) tema = 'servicio';

if (msg.match(/masti/)) velero = 'masti';
else if (msg.match(/brama/)) velero = 'brama';
else if (msg.match(/marejada/)) velero = 'marejada';
else if (msg.match(/brisa/)) velero = 'brisa';

// Generar resumen breve para historial
const resumen = `${agentData.nombre || 'Cliente'} pregunto: ${agentData.mensaje.substring(0, 80)}. ${agentData.agente} respondio.`;

// ManyChat espera JSON con estos campos para usar en el flujo
return [{
  json: {
    version: "v2",
    content: {
      messages: [
        {
          type: "text",
          text: respuesta
        }
      ],
      actions: [
        {
          action: "set_field_value",
          field_name: "ultimo_agente",
          value: agentData.agente
        },
        {
          action: "set_field_value",
          field_name: "ultima_interaccion",
          value: new Date().toISOString()
        },
        {
          action: "set_field_value",
          field_name: "historial_resumen",
          value: resumen
        },
        {
          action: "set_field_value",
          field_name: "tema_consulta",
          value: tema
        },
        {
          action: "set_field_value",
          field_name: "velero_interes",
          value: velero
        }
      ]
    }
  }
}];
